import { randomUUID } from 'crypto';
import { Router, type Request, type Response } from 'express';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

const commentsRouter = Router();

function isUuid(value: string): boolean {
  return UUID_REGEX.test(value);
}

function parseId(value: unknown): string | null {
  return typeof value === 'string' && isUuid(value) ? value : null;
}

function mapCommentRow(row: any) {
  return {
    id: row.id,
    document_id: row.document_id,
    comment_id: row.comment_id,
    parent_id: row.parent_id,
    author_id: row.author_id,
    content: row.content,
    resolved_at: row.resolved_at,
    created_at: row.created_at,
    updated_at: row.updated_at,
  };
}

async function getDocumentForWorkspace(documentId: string, workspaceId: string) {
  const document = await pool.query('SELECT id FROM documents WHERE id = $1 AND workspace_id = $2', [documentId, workspaceId]);
  return document.rowCount > 0;
}

async function getCommentWithWorkspace(id: string) {
  return pool.query('SELECT c.*, d.workspace_id FROM comments c JOIN documents d ON d.id = c.document_id WHERE c.id = $1', [id]);
}

commentsRouter.get('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseId(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  if (!(await getDocumentForWorkspace(documentId, req.workspaceId))) {
    return res.status(404).json({ error: 'Document not found' });
  }

  const rows = await pool.query(
    'SELECT id, document_id, comment_id, parent_id, author_id, content, resolved_at, created_at, updated_at FROM comments WHERE document_id = $1 ORDER BY comment_id ASC, created_at ASC',
    [documentId]
  );

  const threads = new Map<string, any>();
  for (const row of rows.rows) {
    const comment = mapCommentRow(row);
    const existing = threads.get(comment.comment_id) ?? { comment_id: comment.comment_id, comments: [] };
    existing.comments.push(comment);
    threads.set(comment.comment_id, existing);
  }

  return res.json({ comments: Array.from(threads.values()) });
});

commentsRouter.post('/documents/:id/comments', authMiddleware, async (req: Request, res: Response) => {
  const documentId = parseId(req.params.id);
  if (!documentId) return res.status(400).json({ error: 'Invalid document id' });

  const document = await pool.query('SELECT id, workspace_id FROM documents WHERE id = $1', [documentId]);
  if (document.rowCount === 0) return res.status(404).json({ error: 'Document not found' });
  if (document.rows[0].workspace_id !== req.workspaceId) return res.status(403).json({ error: 'Forbidden' });

  const content = typeof req.body?.content === 'string' ? req.body.content.trim() : '';
  if (!content) return res.status(400).json({ error: 'content is required' });

  const parentId = parseId(req.body?.parent_id);
  if (req.body?.parent_id && !parentId) return res.status(400).json({ error: 'Invalid parent_id' });

  const providedCommentId = parseId(req.body?.comment_id);
  if (req.body?.comment_id && !providedCommentId) return res.status(400).json({ error: 'Invalid comment_id' });

  let threadCommentId = providedCommentId ?? randomUUID();

  if (parentId) {
    const parent = await pool.query('SELECT id, comment_id, document_id FROM comments WHERE id = $1', [parentId]);
    if (parent.rowCount === 0 || parent.rows[0].document_id !== documentId) return res.status(404).json({ error: 'Parent comment not found' });
    threadCommentId = parent.rows[0].comment_id;
  }

  const inserted = await pool.query(
    'INSERT INTO comments (id, document_id, comment_id, parent_id, author_id, content) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id, document_id, comment_id, parent_id, author_id, content, resolved_at, created_at, updated_at',
    [randomUUID(), documentId, threadCommentId, parentId, req.userId!, content]
  );

  return res.status(201).json(mapCommentRow(inserted.rows[0]));
});

