    const response = await apiPost(`/api/documents/${documentId}/comments`, data);
    if (!response.ok) throw new Error('Failed to create comment thread');
    return response.json();
  });
}

export function useCreateCommentThread(documentId: string) {
  return useCreateComment(documentId);
}

export function useCreateCommentReply(documentId: string) {
  return useDocumentCommentsMutation(documentId, async (data: CreateCommentReplyInput) => {
    const response = await apiPost(`/api/documents/${documentId}/comments`, data);
    if (!response.ok) throw new Error('Failed to create comment reply');
    return response.json();
  });
}

export function useUpdateComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId, content }: UpdateCommentInput) => {
    const response = await apiPatch(`/api/comments/${commentId}`, { content });
    if (!response.ok) throw new Error('Failed to update comment');
    return response.json();
  });
}

export function useResolveComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId }: ResolveCommentInput) => {
    const response = await apiPost(`/api/comments/${commentId}/resolve`, {});
    if (!response.ok) throw new Error('Failed to resolve comment');
    return response.json();
  });
}

export function useDeleteComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId }: DeleteCommentInput) => {
    const response = await apiDelete(`/api/comments/${commentId}`);
    if (!response.ok && response.status !== 204) throw new Error('Failed to delete comment');
    return null;
  });
}

