    const uploadUrl = await generateS3PresignedUrl(storageKey, mimeType, sizeBytes);
    res.status(201).json({
      id: fileId,
      uploadUrl,
      storageKey,
      expiresInSeconds: PRESIGNED_URL_EXPIRES_IN,
      method: 'PUT',
      downloadUrl: null,
      status: 'pending',
    });
    return;
  }

  res.status(201).json({
    id: fileId,
    uploadUrl: `/api/files/upload/${fileId}`,
    storageKey,
    expiresInSeconds: PRESIGNED_URL_EXPIRES_IN,
    method: 'POST',
    downloadUrl: null,
    status: 'pending',
  });
});

