import { Router, Request, Response } from 'express';
import express from 'express';
import multer from 'multer';
import { pool } from '../db/client.js';
import { z } from 'zod';
import { randomUUID } from 'crypto';
import { mkdir, writeFile } from 'fs/promises';
import { createReadStream } from 'fs';
import path, { basename, dirname, join } from 'path';
import { authMiddleware } from '../middleware/auth.js';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { getAppEnvConfig } from '../config/env.js';
import { usesS3Storage } from '../utils/runtime-storage.js';

const MAX_FILE_SIZE = 1024 * 1024 * 1024;
const PRESIGNED_URL_EXPIRES_IN = 15 * 60;
const AWS_REGION = process.env.AWS_REGION || 'us-east-1';
const { uploadsDir: LOCAL_UPLOADS_DIR } = getAppEnvConfig();
const S3_BUCKET_NAME = process.env.S3_UPLOADS_BUCKET || null;

const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const BLOCKED_EXTENSIONS = new Set([
  '.exe', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif', '.vbs', '.vbe', '.js', '.jse', '.ws', '.wsf', '.wsc', '.wsh',
  '.dll', '.sys', '.drv', '.cpl', '.ocx', '.lnk', '.inf', '.reg', '.msc', '.app', '.dmg', '.pkg', '.sh', '.bash', '.deb',
  '.rpm', '.run', '.jar', '.ps1', '.psm1', '.psd1',
]);

const uploadRequestSchema = z.object({
  filename: z.string().min(1).max(255),
  mimeType: z.string().min(1).max(100),
  sizeBytes: z.coerce.number().int().positive().max(MAX_FILE_SIZE),
});

const localUploadSchema = z.object({
  fileId: z.string().uuid(),
});

function isDangerousExtension(filename: string): boolean {
  const clean = basename(filename).toLowerCase();
  const dot = clean.lastIndexOf('.');
  return dot !== -1 && BLOCKED_EXTENSIONS.has(clean.slice(dot));
}

function getS3Client(): S3Client {
  return new S3Client({ region: AWS_REGION });
}

function buildDownloadUrl(fileId: string): string {
  return `/api/files/${fileId}`;
}

function buildUploadPath(fileId: string): string {
  return `/api/files/upload/${fileId}`;
}

function buildLocalStorageKey(fileId: string, filename: string): string {
  const ext = path.extname(filename);
  return `${fileId}${ext}`;
}

export const filesRouter = Router();
const multipartUpload = multer({ storage: multer.memoryStorage(), limits: { fileSize: MAX_FILE_SIZE } });

async function generateS3PresignedUrl(s3Key: string, contentType: string, sizeBytes: number): Promise<string> {
  if (!S3_BUCKET_NAME) throw new Error('S3 uploads bucket is not configured');
  const command = new PutObjectCommand({ Bucket: S3_BUCKET_NAME, Key: s3Key, ContentType: contentType, ContentLength: sizeBytes });
  return getSignedUrl(getS3Client(), command, { expiresIn: PRESIGNED_URL_EXPIRES_IN });
}

filesRouter.post('/upload-request', authMiddleware, async (req: Request, res: Response) => {
  const parsed = uploadRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid input', details: parsed.error.flatten() });
    return;
  }

  const { filename, mimeType, sizeBytes } = parsed.data;
  if (isDangerousExtension(filename)) {
    res.status(400).json({ error: 'File type not allowed' });
    return;
  }

  const fileId = randomUUID();
  const storageKey = buildLocalStorageKey(fileId, filename);
  await pool.query(
    `INSERT INTO files (id, workspace_id, uploaded_by, filename, mime_type, size_bytes, s3_key, status)
     VALUES ($1, $2, $3, $4, $5, $6, $7, 'pending')`,
    [fileId, req.workspaceId, req.userId, filename, mimeType, sizeBytes, storageKey]
  );

  if (usesS3Storage() && S3_BUCKET_NAME) {
    const uploadUrl = await generateS3PresignedUrl(storageKey, mimeType, sizeBytes);
    res.status(201).json({ fileId, status: 'pending', uploadUrl, method: 'PUT', downloadUrl: null, metadataUrl: buildDownloadUrl(fileId), s3Key: storageKey });
    return;
  }

  res.status(201).json({ fileId, status: 'pending', uploadUrl: buildUploadPath(fileId), method: 'POST', downloadUrl: null, metadataUrl: buildDownloadUrl(fileId), uploadEndpoint: buildUploadPath(fileId), s3Key: storageKey });
});

filesRouter.post('/upload/:id', authMiddleware, multipartUpload.single('file'), async (req: Request, res: Response) => {
  const fileId = req.params.id;
  if (!UUID_REGEX.test(fileId)) {
    res.status(400).json({ error: 'Invalid file ID format' });
    return;
  }

  const parsed = localUploadSchema.safeParse(req.body);
  if (!parsed.success) {
    res.status(400).json({ error: 'Invalid input', details: parsed.error.flatten() });
    return;
  }

  const fileRow = await pool.query(`SELECT id, filename, mime_type, size_bytes, s3_key, status FROM files WHERE id = $1 AND workspace_id = $2 AND status = 'pending'`, [fileId, req.workspaceId]);
  if (!fileRow.rows[0]) {
    res.status(404).json({ error: 'File not found or already uploaded' });
    return;
  }

  const uploadedFile = req.file;
  if (!uploadedFile) {
    res.status(400).json({ error: 'Missing file upload' });
    return;
  }

  const filePath = join(LOCAL_UPLOADS_DIR, fileRow.rows[0].s3_key);
  await mkdir(dirname(filePath), { recursive: true });
  await writeFile(filePath, uploadedFile.buffer);

  const downloadUrl = buildDownloadUrl(fileId);
  await pool.query(`UPDATE files SET status = 'uploaded', cdn_url = $1, updated_at = NOW() WHERE id = $2`, [downloadUrl, fileId]);
  res.status(200).json({ fileId, status: 'uploaded', cdnUrl: downloadUrl, downloadUrl });
});

filesRouter.get('/:id', authMiddleware, async (req: Request, res: Response) => {
  const fileId = req.params.id;
  if (!UUID_REGEX.test(fileId)) {
    res.status(400).json({ error: 'Invalid file ID format' });
