    return;
  }

  const file = result.rows[0];
  const downloadUrl = file.status === 'uploaded' ? (usesS3Storage() ? (file.cdn_url ?? null) : buildDownloadUrl(fileId)) : null;
  res.json({
    id: file.id,
    filename: file.filename,
    mimeType: file.mime_type,
    sizeBytes: file.size_bytes,
    s3Key: file.s3_key,
    status: file.status,
    createdAt: file.created_at,
    downloadUrl,
  });
});

