import { getVisibilityContext, VISIBILITY_FILTER_SQL } from '../middleware/visibility.js';
import { authMiddleware } from '../middleware/auth.js';

type RouterType = ReturnType<typeof Router>;
const router: RouterType = Router();

const uuidParamSchema = z.string().uuid();

const linkSyncSchema = z.object({
  links: z.array(z.string().uuid()).default([]),
  mentions: z.array(z.string().uuid()).default([]),
});

async function assertVisibleDocumentOrThrow(id: string, workspaceId: string, userId: string, isAdmin: boolean) {
  const docResult = await pool.query(
    `SELECT id FROM documents
     WHERE id = $1 AND workspace_id = $2
       AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
    [id, workspaceId, userId, isAdmin]
  );

  return docResult.rows.length > 0;
}

router.get('/:id/backlinks', authMiddleware, async (req: Request, res: Response) => {
  try {
    const parsedId = uuidParamSchema.safeParse(req.params.id);
    if (!parsedId.success) {
      res.status(400).json({ error: 'Invalid document ID' });
      return;
    }

    const id = parsedId.data;
    const userId = req.userId!;
    const workspaceId = req.workspaceId!;
    const { isAdmin } = await getVisibilityContext(userId, workspaceId);

    const visible = await assertVisibleDocumentOrThrow(id, workspaceId, userId, isAdmin);
    if (!visible) {
      res.status(404).json({ error: 'Document not found' });
      return;
    }

    const result = await pool.query(
      `SELECT d.id, d.document_type, d.title
       FROM document_links dl
       JOIN documents d ON dl.source_id = d.id
       WHERE dl.target_id = $1 AND d.workspace_id = $2
         AND ${VISIBILITY_FILTER_SQL('d', '$3', '$4')}
       ORDER BY dl.created_at DESC`,
      [id, workspaceId, userId, isAdmin]
    );

    res.json(result.rows.map((row) => ({ id: row.id, type: row.document_type, title: row.title })));
  } catch (err) {
    console.error('Get backlinks error:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.post('/:id/links', authMiddleware, async (req: Request, res: Response) => {
  try {
    const parsedId = uuidParamSchema.safeParse(req.params.id);
    if (!parsedId.success) {
      res.status(400).json({ error: 'Invalid document ID' });
      return;
    }

    const id = parsedId.data;
    const userId = req.userId!;
    const workspaceId = req.workspaceId!;
    const parsed = linkSyncSchema.safeParse(req.body);

    if (!parsed.success) {
      res.status(400).json({ error: 'Invalid input', details: parsed.error.errors });
      return;
    }

    const linkIds = Array.from(new Set([...parsed.data.links, ...parsed.data.mentions]));
    const { isAdmin } = await getVisibilityContext(userId, workspaceId);

    const visible = await assertVisibleDocumentOrThrow(id, workspaceId, userId, isAdmin);
    if (!visible) {
      res.status(404).json({ error: 'Document not found' });
      return;
    }

    if (linkIds.length > 0) {
      const targetResult = await pool.query(
        `SELECT id FROM documents
         WHERE id = ANY($1::uuid[]) AND workspace_id = $2
           AND ${VISIBILITY_FILTER_SQL('documents', '$3', '$4')}`,
        [linkIds, workspaceId, userId, isAdmin]
      );

      if (targetResult.rows.length !== linkIds.length) {
        res.status(400).json({ error: 'One or more target documents not found' });
        return;
      }
    }

    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      await client.query('DELETE FROM document_links WHERE source_id = $1', [id]);

      if (linkIds.length > 0) {
        const values = linkIds.map((_, idx) => `($${idx * 2 + 1}::uuid, $${idx * 2 + 2}::uuid)`).join(', ');
        const params = linkIds.flatMap((targetId) => [id, targetId]);
        await client.query(
          `INSERT INTO document_links (source_id, target_id)
           VALUES ${values}
           ON CONFLICT (source_id, target_id) DO UPDATE SET
             source_id = EXCLUDED.source_id,
             target_id = EXCLUDED.target_id`,
          params
        );
      }

      await client.query('COMMIT');
      res.status(200).json({ document_id: id, linked_document_ids: linkIds });
    } catch (err) {
      await client.query('ROLLBACK');
      throw err;
    } finally {
      client.release();
    }
  } catch (err) {
    console.error('Update links error:', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

export default router;

declare global {
  namespace Express {
    interface Request {
      user?: {
        id: string;
        email: string;
        name: string;
        workspaceId: string;
      };
    }
  }
}

