export async function uploadFile(file: File, onProgress?: ProgressCallback, signal?: AbortSignal): Promise<UploadResult> {
  if (signal?.aborted) throw new DOMException('Upload cancelled', 'AbortError');

  const progressState: UploadProgress = { fileId: '', progress: 0, status: 'pending' };
  const updateProgress = (updates: Partial<UploadProgress>) => {
    Object.assign(progressState, updates);
    trackUploadProgress(onProgress, { ...progressState });
  };

  try {
    updateProgress({ status: 'pending', progress: 10 });
    const request = await requestUpload(file, signal);
    updateProgress({ fileId: request.fileId, progress: 25 });

    const uploadUrl = request.isLocalUpload ? `${API_BASE}${request.uploadUrl}` : request.uploadUrl;
    const method = getUploadMethod(request);
    const mimeType = getUploadMimeType(file);

    updateProgress({ status: 'uploading', progress: 40 });
    const uploadRes = await fetch(uploadUrl, {
      method,
      headers:
        method === 'PUT'
          ? { 'Content-Type': mimeType }
          : { 'x-csrf-token': await getCsrfToken(), 'Content-Type': mimeType },
      credentials: request.isLocalUpload ? 'include' : undefined,
      body: file,
      signal,
    });

    if (!uploadRes.ok) {
      const error = await uploadRes.json().catch(() => ({}));
      throw new Error(error.error || 'Failed to upload file');
    }

    updateProgress({ status: request.isLocalUpload ? 'complete' : 'confirming', progress: request.isLocalUpload ? 100 : 85 });
    const confirmed = request.cdnUrl ? { cdnUrl: request.cdnUrl } : await confirmUpload(request.fileId, signal);
    const cdnUrl = confirmed.cdnUrl;
    const result: UploadResult = {
      fileId: request.fileId,
      url: cdnUrl,
      cdnUrl,
      name: file.name,
      size: file.size,
      mimeType,
    };
    updateProgress({ status: 'complete', progress: 100 });
    return result;
  } catch (error) {
    updateProgress({ status: 'error', error: error instanceof Error ? error.message : 'Upload failed' });
    throw error;
  }
}

