    13	interface UploadContextValue extends UploadTrackerSnapshot {
    14	  isUploading: boolean;
    15	  clearUploads: () => void;
    16	}
    17	
    18	const UploadContext = createContext<UploadContextValue | null>(null);
    19	
    20	export function UploadProvider({ children }: { children: ReactNode }) {
    21	  const snapshot = useSyncExternalStore(subscribeToUploads, getUploadSnapshot, getUploadSnapshot);
    22	  const isUploading = snapshot.uploadCount > 0;
    23	
    24	  const clearTrackedUploads = useCallback(() => {
    25	    clearUploads();
    26	  }, []);
    27	
    28	  useEffect(() => {
    29	    if (!isUploading) return;
    30	
    31	    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
    32	      e.preventDefault();
    33	      e.returnValue = '';
    34	    };
    35	
    36	    window.addEventListener('beforeunload', handleBeforeUnload);
    37	    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    38	  }, [isUploading]);
    39	
    40	  const value = useMemo<UploadContextValue>(
    41	    () => ({
    42	      ...snapshot,
    43	      isUploading,
    44	      clearUploads: clearTrackedUploads,
    45	    }),
    46	    [snapshot, isUploading, clearTrackedUploads]
    47	  );
    48	
    49	  return <UploadContext.Provider value={value}>{children}</UploadContext.Provider>;
    50	}
    51	
    52	export function useUploads() {
    53	  const context = useContext(UploadContext);
