    57	  return context;
    58	}
    59	
    60	export function useUploadNavigationWarning(): UploadNavigationWarningState {
    61	  const { isUploading, uploadCount, activeUploads, clearUploads } = useUploads();
    62	
    63	  return {
    64	    isBlocked: isUploading,
    65	    uploadCount: snapshot.uploadCount,
    66	    activeUploads: snapshot.activeUploads,
