import { createContext, useContext, useEffect, ReactNode, useCallback, useMemo, useSyncExternalStore } from 'react';
import {
  clearUploads,
  getUploadSnapshot,
  subscribeToUploads,
} from '@/services/uploadTracker';
import type { UploadNavigationWarningState, UploadTrackerSnapshot } from '@/services/uploadTracker';

interface UploadContextValue extends UploadTrackerSnapshot {
  isUploading: boolean;
  clearUploads: () => void;
}

const UploadContext = createContext<UploadContextValue | null>(null);

export function UploadProvider({ children }: { children: ReactNode }) {
  const snapshot = useSyncExternalStore(subscribeToUploads, getUploadSnapshot, getUploadSnapshot);
  const isUploading = snapshot.uploadCount > 0;

  const clearTrackedUploads = useCallback(() => {
    clearUploads();
  }, []);

  useEffect(() => {
    if (!isUploading) return;

    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [isUploading]);

  const value = useMemo<UploadContextValue>(
    () => ({
      ...snapshot,
      isUploading,
      clearUploads: clearTrackedUploads,
    }),
    [snapshot, isUploading, clearTrackedUploads]
  );

  return <UploadContext.Provider value={value}>{children}</UploadContext.Provider>;
}

export function useUploads() {
  const context = useContext(UploadContext);
  if (!context) {
    throw new Error('useUploads must be used within an UploadProvider');
  }
  return context;
}

export function useUploadNavigationWarning(): UploadNavigationWarningState {
  const { isUploading, uploadCount, activeUploads, clearUploads } = useUploads();

  return {
    isBlocked: isUploading,
    uploadCount: snapshot.uploadCount,
    activeUploads: snapshot.activeUploads,
    proceed: clearUploads,
    stay: () => undefined,
  };
}

