/**
 * Upload Navigation Warning Modal
 * Shows when user tries to navigate away while uploads are in progress
 */
import { useMemo, useState } from 'react';
import { createPortal } from 'react-dom';
import { useUploadNavigationWarning } from '@/contexts/UploadContext';

function usePortalTarget(): HTMLElement | null {
  return useMemo(() => (typeof document === 'undefined' ? null : document.body), []);
}

export function UploadNavigationWarning() {
  const { isBlocked, uploadCount, activeUploads, proceed, stay } = useUploadNavigationWarning();
  const portalTarget = usePortalTarget();
  const [open, setOpen] = useState(true);

  if (!isBlocked || !portalTarget || !open) return null;

  return createPortal(
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="w-full max-w-md rounded-lg bg-background p-6 shadow-xl">
        <h2 className="text-lg font-semibold text-foreground">Uploads in Progress</h2>
        <p className="mt-2 text-sm text-muted">
          You have {uploadCount} upload{uploadCount !== 1 ? 's' : ''} in progress.
          {activeUploads.length > 0 ? ` Current upload: ${activeUploads[0].filename}.` : ''}
          Leaving this page will cancel {uploadCount !== 1 ? 'them' : 'it'}.
        </p>
        <div className="mt-6 flex justify-end gap-3">
          <button
            type="button"
            onClick={() => {
              stay();
              setOpen(false);
            }}
            className="rounded-md px-4 py-2 text-sm font-medium text-foreground hover:bg-muted/20"
          >
            Stay on Page
          </button>
          <button
            type="button"
            onClick={() => {
              proceed();
              setOpen(false);
            }}
            className="rounded-md bg-red-500 px-4 py-2 text-sm font-medium text-white hover:bg-red-600"
          >
            Leave & Cancel Uploads
          </button>
        </div>
      </div>
    </div>,
    portalTarget
  );
}

