function invalidateCommentQueries(queryClient: ReturnType<typeof useQueryClient>, documentId: string) {
  queryClient.invalidateQueries({ queryKey: ['comments', documentId] });
}

function parseCommentThreads(response: Response) {
  return response.json() as Promise<CommentThread[]>;
}

export function useCommentsQuery(documentId: string | undefined) {
  return useQuery<CommentThread[]>({
    queryKey: ['comments', documentId],
    queryFn: async () => {
      if (!documentId) return [];
      const response = await apiGet(`/api/documents/${documentId}/comments`);
      if (!response.ok) throw new Error('Failed to fetch comment threads');
      return parseCommentThreads(response);
    },
    enabled: !!documentId,
  });
}

export function useCreateComment(documentId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (data: CreateCommentThreadInput) => {
      const response = await apiPost(`/api/documents/${documentId}/comments`, data);
      if (!response.ok) throw new Error('Failed to create comment thread');
      return response.json();
    },
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

export function useCreateCommentThread(documentId: string) {
  return useCreateComment(documentId);
}

export function useCreateCommentReply(documentId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (data: CreateCommentReplyInput) => {
      const response = await apiPost(`/api/documents/${documentId}/comments/${data.parent_id}/replies`, {
        content: data.content,
      });
      if (!response.ok) throw new Error('Failed to create comment reply');
      return response.json();
    },
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

export function useUpdateComment(documentId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ commentId, content }: UpdateCommentInput) => {
      const response = await apiPatch(`/api/documents/${documentId}/comments/${commentId}`, { content });
      if (!response.ok) throw new Error('Failed to update comment');
      return response.json();
    },
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

export function useResolveComment(documentId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ commentId, resolved }: ResolveCommentInput) => {
      const response = await apiPatch(`/api/documents/${documentId}/comments/${commentId}/resolve`, { resolved });
      if (!response.ok) throw new Error('Failed to resolve comment');
      return response.json();
    },
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

export function useDeleteComment(documentId: string) {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ commentId }: DeleteCommentInput) => {
      const response = await apiDelete(`/api/documents/${documentId}/comments/${commentId}`);
      if (!response.ok) throw new Error('Failed to delete comment');
      return response.json();
    },
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

