{"success":true,"content":"     1	/**
     2	 * Isolated E2E Test Environment
     3	 *
     4	 * Each Playwright worker gets its own:
     5	 * - PostgreSQL container (via testcontainers)
     6	 * - API server instance (dynamic port)
     7	 * - Vite preview server (dynamic port, lightweight static server)
     8	 *
     9	 * CRITICAL: We use `vite preview` instead of `vite dev` because:
    10	 * - vite dev starts HMR, file watchers, and uses 300-500MB per instance
    11	 * - vite preview is a lightweight static server using ~30-50MB
    12	 * - Running 8 vite dev servers caused 90GB memory explosion and system crash
    13	 *
    14	 * This eliminates flakiness from shared database state.
    15	 */
    16	
    17	import { test as base } from '@playwright/test';
    18	import { PostgreSqlContainer, StartedPostgreSqlContainer } from '@testcontainers/postgresql';
    19	import { spawn, ChildProcess } from 'child_process';
    20	import { Pool } from 'pg';
    21	import { existsSync } from 'fs';
    22	import path from 'path';
    23	import getPort, { portNumbers } from 'get-port';
    24	import bcrypt from 'bcryptjs';
    25	import os from 'os';
    26	import { ensureDatabaseSchema } from '../../api/src/db/bootstrap.js';
    27	
    28	/**
    29	 * Get port for a worker with collision avoidance.
    30	 *
    31	 * Each worker gets its own port range to avoid race conditions when
    32	 * multiple workers call getPort() simultaneously. Uses a base port of 50000
    33	 * with 100-port ranges per worker:
    34	 * - Worker 0: 50000-50099
    35	 * - Worker 1: 50100-50199
    36	 * - etc.
    37	 */
    38	async function getWorkerPort(workerIndex: number): Promise<number> {
    39	  const BASE_PORT = 10000;
    40	  const MAX_PORT = 65535;
    41	  const PORTS_PER_WORKER = 100;
    42	  const AVAILABLE_RANGE = MAX_PORT - BASE_PORT; // 55535 ports available
    43	  const MAX_WORKERS = Math.floor(AVAILABLE_RANGE / PORTS_PER_WORKER); // 555 workers max
    44	
    45	  // Wrap worker index to stay within valid port range
    46	  const wrappedIndex = workerIndex % MAX_WORKERS;
    47	  const startPort = BASE_PORT + wrappedIndex * PORTS_PER_WORKER;
    48	  const endPort = Math.min(startPort + PORTS_PER_WORKER - 1, MAX_PORT);
    49	
    50	  return getPort({ port: portNumbers(startPort, endPort) });
    51	}
    52	
    53	// Get project root (fixtures is at e2e/fixtures/, so go up 2 levels)
    54	const PROJECT_ROOT = path.resolve(__dirname, '../..');
    55	
    56	/**
    57	 * Get available system memory in GB.
    58	 * Used to warn if running too many workers.
    59	 */
    60	function getAvailableMemoryGB(): number {
    61	  const freeMem = os.freemem();
    62	  return freeMem / (1024 * 1024 * 1024);
    63	}
    64	
    65	/**
    66	 * Calculate safe number of workers based on available memory.
    67	 * Each worker needs roughly: 150MB (Postgres) + 100MB (API) + 50MB (preview) = ~300MB minimum
    68	 * Add buffer for tests, browser, etc = ~500MB per worker safe estimate
    69	 */
    70	function getSafeWorkerCount(): number {
    71	  const availableGB = getAvailableMemoryGB();
    72	  const memPerWorker = 0.5; // 500MB per worker
    73	  const reserveGB = 2; // Keep 2GB free for OS and other processes
    74	  const safeCount = Math.max(1, Math.floor((availableGB - reserveGB) / memPerWorker));
    75	  return Math.min(safeCount, 8); // Cap at 8 regardless
    76	}
    77	
