import { test, expect, Page } from './fixtures/isolated-env';

/**
 * File Upload API Tests
 *
 * These tests verify the upload flow end-to-end:
 * - authenticated upload requests return a usable upload URL
 * - the uploaded file can be finalized into a persisted CDN URL
 * - the stored file record exposes a URL that the editor can embed
 */

async function loginAndGetCookies(page: Page): Promise<string> {
  await page.goto('/login');
  await page.locator('#email').fill('dev@ship.local');
  await page.locator('#password').fill('admin123');
  await page.getByRole('button', { name: 'Sign in', exact: true }).click();
  await expect(page).not.toHaveURL('/login', { timeout: 5000 });

  const cookies = await page.context().cookies();
  return cookies.map(c => `${c.name}=${c.value}`).join('; ');
}

async function getCsrfToken(page: Page, apiUrl: string): Promise<string> {
  const response = await page.request.get(`${apiUrl}/api/csrf-token`);
  const data = await response.json();
  return data.token;
}

test.describe('File Upload API', () => {
  test('returns a usable upload URL and persisted file URL when authenticated', async ({ page, apiServer }) => {
    const API_URL = apiServer.url;
    await loginAndGetCookies(page);
    const csrfToken = await getCsrfToken(page, API_URL);

    const uploadResponse = await page.request.post(`${API_URL}/api/files/upload`, {
      headers: { 'x-csrf-token': csrfToken },
      data: {
        filename: 'test-image.png',
        mimeType: 'image/png',
        sizeBytes: 1024,
      },
    });

    expect(uploadResponse.ok()).toBeTruthy();
    const uploadData = await uploadResponse.json();
    expect(uploadData).toMatchObject({
      fileId: expect.any(String),
      uploadUrl: expect.any(String),
      s3Key: expect.any(String),
    });
    expect(uploadData.uploadUrl.length).toBeGreaterThan(0);

    const isLocalUpload = uploadData.uploadUrl.startsWith('/api/files/');
    if (isLocalUpload) {
      const pngBuffer = Buffer.from(
        'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8DwHwAFBQIAX8jx0gAAAABJRU5ErkJggg==',
        'base64'
      );

      const localUploadResponse = await page.request.post(`${API_URL}${uploadData.uploadUrl}`, {
        headers: {
          'Content-Type': 'image/png',
          'x-csrf-token': csrfToken,
        },
        data: pngBuffer,
      });
      expect(localUploadResponse.ok()).toBeTruthy();
    }

    const fileResponse = await page.request.get(`${API_URL}/api/files/${uploadData.fileId}`);
    expect(fileResponse.ok()).toBeTruthy();

    const fileData = await fileResponse.json();
    expect(fileData.cdn_url).toBeTruthy();
    expect(fileData.status).toBe('uploaded');
    expect(fileData.cdn_url).toMatch(/^https?:\/\//);
  });
});

import { test, expect, Page } from './fixtures/isolated-env';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

/**
 * Image Upload E2E Tests
 *
 * These tests verify that TipTap image insertion produces a renderable image node,
 * then swaps the temporary upload preview for a persisted URL that survives reload.
 */

async function createNewDocument(page: Page) {
  await page.goto('/docs');
  await page.waitForLoadState('networkidle');

  const currentUrl = page.url();
  const sidebarButton = page.locator('aside').getByRole('button', { name: /new|create|\+/i }).first();
  const mainButton = page.getByRole('button', { name: 'New Document', exact: true });

  if (await sidebarButton.isVisible({ timeout: 2000 })) {
    await sidebarButton.click();
  } else {
    await expect(mainButton).toBeVisible({ timeout: 5000 });
    await mainButton.click();
  }

  await page.waitForFunction(
    (oldUrl) => window.location.href !== oldUrl && /\/documents\/[a-f0-9-]+/.test(window.location.href),
    currentUrl,
    { timeout: 10000 }
  );

  await expect(page.locator('.ProseMirror')).toBeVisible({ timeout: 5000 });
  await expect(page.locator('textarea[placeholder="Untitled"]')).toBeVisible({ timeout: 3000 });
}

function createTestImageFile(): string {
  const pngBuffer = Buffer.from(
    'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8DwHwAFBQIAX8jx0gAAAABJRU5ErkJggg==',
    'base64'
  );
  const tmpPath = path.join(os.tmpdir(), `test-image-${Date.now()}.png`);
  fs.writeFileSync(tmpPath, pngBuffer);
  return tmpPath;
}

async function insertImageViaSlashCommand(page: Page): Promise<void> {
  const editor = page.locator('.ProseMirror');
  await editor.click();
  await page.waitForTimeout(300);
  await page.keyboard.type('/image');
  await page.waitForTimeout(500);

  const tmpPath = createTestImageFile();
  const fileChooserPromise = page.waitForEvent('filechooser');
  await page.keyboard.press('Enter');
  const fileChooser = await fileChooserPromise;
  await fileChooser.setFiles(tmpPath);
  setTimeout(() => {
    try { fs.unlinkSync(tmpPath); } catch {}
  }, 5000);
}

test.describe('Images', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/login');
    await page.locator('#email').fill('dev@ship.local');
    await page.locator('#password').fill('admin123');
    await page.getByRole('button', { name: 'Sign in', exact: true }).click();
    await expect(page).not.toHaveURL('/login', { timeout: 5000 });
  });

  test('renders an image node and persists its upload URL after reload', async ({ page }) => {
    await createNewDocument(page);
    await insertImageViaSlashCommand(page);

    const editor = page.locator('.ProseMirror');
    const img = editor.locator('img').first();
    await expect(img).toBeVisible({ timeout: 5000 });

    await page.waitForFunction(
      () => {
        const img = document.querySelector('.ProseMirror img');
        if (!img) return false;
        const src = img.getAttribute('src') || '';
        return src.startsWith('http') || src.includes('/api/files');
      },
      { timeout: 15000 }
    );

    const imgSrc = await img.getAttribute('src');
    expect(imgSrc).toBeTruthy();
    expect(imgSrc).not.toContain('data:');

    await page.reload();
    await expect(page.locator('.ProseMirror')).toBeVisible({ timeout: 5000 });
    await expect(page.locator('.ProseMirror img')).toBeVisible({ timeout: 5000 });
  });
});

