     5	import { createContext, useContext, useEffect, ReactNode, useCallback, useMemo, useSyncExternalStore } from 'react';
     6	import { clearUploads, getUploadSnapshot, subscribeToUploads } from '@/services/uploadTracker';
     7	import type { UploadNavigationWarningState, UploadTrackerSnapshot } from '@/services/uploadTracker';
     8	
     9	interface UploadContextValue extends UploadTrackerSnapshot {
    10	  isUploading: boolean;
    11	  clearUploads: () => void;
    12	}
    13	
    14	const UploadContext = createContext<UploadContextValue | null>(null);
    15	
    16	export function UploadProvider({ children }: { children: ReactNode }) {
    17	  const snapshot = useSyncExternalStore(subscribeToUploads, getUploadSnapshot, getUploadSnapshot);
    18	  const isUploading = snapshot.uploadCount > 0;
    19	
    20	  const clearTrackedUploads = useCallback(() => {
    21	    clearUploads();
    22	  }, []);
    23	
    24	  useEffect(() => {
    25	    const beforeUnload = (e: BeforeUnloadEvent) => {
    26	      if (!isUploading) return;
    27	      e.preventDefault();
    28	      e.returnValue = '';
    29	    };
    30	
    31	    window.addEventListener('beforeunload', beforeUnload);
    32	    return () => window.removeEventListener('beforeunload', beforeUnload);
    33	  }, [isUploading]);
    34	
    35	  const value = useMemo<UploadContextValue>(
    36	    () => ({
    37	      ...snapshot,
    38	      isUploading,
    39	      clearUploads: clearTrackedUploads,
    40	    }),
    41	    [snapshot, isUploading, clearTrackedUploads]
    42	  );
    43	
    44	  return <UploadContext.Provider value={value}>{children}</UploadContext.Provider>;
    45	}
    46	
    47	export function useUploads() {
    48	  const context = useContext(UploadContext);
    49	  if (!context) {
    50	    throw new Error('useUploads must be used within an UploadProvider');
    51	  }
    52	  return context;
    53	}
    54	
    55	export function useUploadNavigationWarning(): UploadNavigationWarningState {
    56	  const { isUploading, uploadCount, activeUploads, clearUploads } = useUploads();
    57	
    58	  const proceed = useCallback(() => {
    59	    clearUploads();
    60	  }, [clearUploads]);
    61	
    62	  return {
    63	    isBlocked: isUploading,
    64	    uploadCount,
    65	    activeUploads,
    66	    proceed,
    67	    stay: () => undefined,
