/**
 * Global upload tracker for navigation warnings
 * Used by both React components (via subscription) and non-React code (TipTap plugins)
 */

export interface UploadInfo {
  id: string;
  filename: string;
  progress: number;
  active: boolean;
}

export interface UploadNavigationWarningState {
  isBlocked: boolean;
  uploadCount: number;
  activeUploads: UploadInfo[];
  proceed: () => void;
  stay: () => void;
}

export interface UploadTrackerSnapshot {
  uploadCount: number;
  activeUploads: UploadInfo[];
}

export interface UploadTrackerListenerState extends UploadTrackerSnapshot {
  hasActiveUploads: boolean;
}

const activeUploads = new Map<string, UploadInfo>();
const listeners = new Set<() => void>();

function cloneUpload(upload: UploadInfo): UploadInfo {
  return { ...upload };
}

function hasWindow(): boolean {
  return typeof window !== 'undefined';
}

function notifyListeners(): void {
  listeners.forEach((listener) => listener());
}

function getBeforeUnloadHandler() {
  return (event: BeforeUnloadEvent) => {
    if (!hasActiveUploads()) return;
    event.preventDefault();
    event.returnValue = '';
    return '';
  };
}

function refreshUploadPresence(): void {
  if (!hasWindow()) return;
  window.onbeforeunload = hasActiveUploads() ? getBeforeUnloadHandler() : null;
}

export function registerUpload(id: string, filename: string): void {
  activeUploads.set(id, { id, filename, progress: 0, active: true });
  refreshUploadPresence();
  notifyListeners();
}

export function updateUploadProgress(id: string, progress: number): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.progress = progress;
  upload.active = true;
  refreshUploadPresence();
  notifyListeners();
}

export function markUploadInactive(id: string): void {
  const upload = activeUploads.get(id);
  if (!upload) return;

  upload.active = false;
  refreshUploadPresence();
  notifyListeners();
}

export function unregisterUpload(id: string): void {
  activeUploads.delete(id);
  refreshUploadPresence();
  notifyListeners();
}

export function clearUploads(): void {
  activeUploads.clear();
  refreshUploadPresence();
  notifyListeners();
}

export function getUploadCount(): number {
  return Array.from(activeUploads.values()).filter((upload) => upload.active).length;
}

export function getActiveUploads(): UploadInfo[] {
  return Array.from(activeUploads.values())
    .filter((upload) => upload.active)
    .map(cloneUpload);
}

export function hasActiveUploads(): boolean {
  return getUploadCount() > 0;
}

export function getUploadSnapshot(): UploadTrackerSnapshot {
  return {
    uploadCount: getUploadCount(),
    activeUploads: getActiveUploads(),
  };
}

export function subscribeToUploads(listener: () => void): () => void {
  listeners.add(listener);
  return () => listeners.delete(listener);
}

export function bindUploadNavigationWarning(onBeforeUnload: (event: BeforeUnloadEvent) => void): () => void {
  if (!hasWindow()) return () => undefined;
  window.addEventListener('beforeunload', onBeforeUnload);
  return () => window.removeEventListener('beforeunload', onBeforeUnload);
}

export function getUploadTrackerListenerState(): UploadTrackerListenerState {
  return {
    ...getUploadSnapshot(),
    hasActiveUploads: hasActiveUploads(),
  };
}

/**
 * Upload Navigation Warning Modal
 * Shows when user tries to navigate away while uploads are in progress
 */
import { useEffect, useMemo, useState } from 'react';
import { createPortal } from 'react-dom';
import { useUploadNavigationWarning } from '@/contexts/UploadContext';

function usePortalTarget(): HTMLElement | null {
  return useMemo(() => (typeof document === 'undefined' ? null : document.body), []);
}

export function UploadNavigationWarning() {
  const { isBlocked, uploadCount, activeUploads, proceed, stay } = useUploadNavigationWarning();
  const portalTarget = usePortalTarget();
  const [open, setOpen] = useState(false);

  useEffect(() => {
    if (isBlocked) setOpen(true);
  }, [isBlocked]);

  if (!isBlocked || !portalTarget || !open) return null;

  return createPortal(
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="w-full max-w-md rounded-lg bg-background p-6 shadow-xl">
        <h2 className="text-lg font-semibold text-foreground">Uploads in Progress</h2>
        <p className="mt-2 text-sm text-muted">
          You have {uploadCount} upload{uploadCount !== 1 ? 's' : ''} in progress.
          {activeUploads.length > 0 ? ` Current upload: ${activeUploads[0].filename}.` : ''}
          Leaving this page will cancel {uploadCount !== 1 ? 'them' : 'it'}.
        </p>
        <div className="mt-6 flex justify-end gap-3">
          <button
            type="button"
            onClick={() => {
              stay();
              setOpen(false);
            }}
            className="rounded-md px-4 py-2 text-sm font-medium text-foreground hover:bg-muted/20"
          >
            Stay on Page
          </button>
          <button
            type="button"
            onClick={() => {
              proceed();
              setOpen(false);
            }}
            className="rounded-md bg-red-500 px-4 py-2 text-sm font-medium text-white hover:bg-red-600"
          >
            Leave & Cancel Uploads
          </button>
        </div>
      </div>
    </div>,
    portalTarget
  );
}

