import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { apiDelete, apiGet, apiPatch, apiPost } from '@/lib/api';

export interface CommentAuthor {
  id: string;
  name: string;
  email?: string;
}

export interface Comment {
  id: string;
  document_id: string;
  comment_id: string;
  parent_id: string | null;
  author_id: string;
  author?: CommentAuthor;
  content: string;
  resolved_at: string | null;
  created_at: string;
  updated_at: string;
}

export interface CommentThread {
  comment_id: string;
  root: Comment | null;
  replies: Comment[];
}

export interface CommentsResponse {
  comments: CommentThread[];
}

export function getCommentThreadResolvedAt(thread: CommentThread): string | null {
  return thread.root?.resolved_at ?? thread.replies[0]?.resolved_at ?? null;
}

export interface CreateCommentThreadInput {
  comment_id: string;
  content: string;
}

export interface CreateCommentReplyInput {
  parent_id: string;
  content: string;
}

export interface UpdateCommentInput {
  commentId: string;
  content: string;
}

export interface ResolveCommentInput {
  commentId: string;
}

export interface DeleteCommentInput {
  commentId: string;
}

function invalidateCommentQueries(queryClient: ReturnType<typeof useQueryClient>, documentId: string) {
  return queryClient.invalidateQueries({ queryKey: ['comments', documentId] });
}

async function parseCommentsResponse(response: Response): Promise<CommentsResponse> {
  return response.json() as Promise<CommentsResponse>;
}

function useDocumentCommentsMutation<TData, TVariables>(
  documentId: string,
  mutationFn: (variables: TVariables) => Promise<TData>
) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn,
    onSuccess: () => invalidateCommentQueries(queryClient, documentId),
  });
}

export function useCommentsQuery(documentId: string | undefined) {
  return useQuery<CommentThread[]>({
    queryKey: ['comments', documentId],
    queryFn: async () => {
      if (!documentId) return [];
      const response = await apiGet(`/api/documents/${documentId}/comments`);
      if (!response.ok) throw new Error('Failed to fetch comments');
      const data = await parseCommentsResponse(response);
      return data.comments;
    },
    enabled: !!documentId,
  });
}

export function useCreateComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async (data: CreateCommentThreadInput) => {
    const response = await apiPost(`/api/documents/${documentId}/comments`, data);
    if (!response.ok) throw new Error('Failed to create comment thread');
    return response.json();
  });
}

export function useCreateCommentThread(documentId: string) {
  return useCreateComment(documentId);
}

export function useCreateCommentReply(documentId: string) {
  return useDocumentCommentsMutation(documentId, async (data: CreateCommentReplyInput) => {
    const response = await apiPost(`/api/documents/${documentId}/comments`, data);
    if (!response.ok) throw new Error('Failed to create comment reply');
    return response.json();
  });
}

export function useUpdateComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId, content }: UpdateCommentInput) => {
    const response = await apiPatch(`/api/comments/${commentId}`, { content });
    if (!response.ok) throw new Error('Failed to update comment');
    return response.json();
  });
}

export function useResolveComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId }: ResolveCommentInput) => {
    const response = await apiPost(`/api/comments/${commentId}/resolve`, {});
    if (!response.ok) throw new Error('Failed to resolve comment');
    return response.json();
  });
}

export function useDeleteComment(documentId: string) {
  return useDocumentCommentsMutation(documentId, async ({ commentId }: DeleteCommentInput) => {
    const response = await apiDelete(`/api/comments/${commentId}`);
    if (!response.ok && response.status !== 204) throw new Error('Failed to delete comment');
    return null;
  });
}

